//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
  let gubunVal = gubun;
  // console.log("scwin.f_Set : " + gubunVal + " : " + scwin.processFlag);

  switch (gubun) {
    case "INIT":
      //초기화
      $c.gus.cfDisableBtnOnly($p, [btn_Print, btn_Print_N, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
      break;
    case "RETRIEVE":
      //조회모드

      // console.log("scwin.processFlag RETRIEVE : " + scwin.processFlag)
      if (scwin.processFlag == "RETRIEVE") {
        $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel]);
        $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Delete, btn_Print, btn_Print_N]);
      } else {
        $c.gus.cfDisableBtnOnly($p, [btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_Print, btn_Print_N]);
        $c.gus.cfEnableBtnOnly($p, [btn_Create]);
      }
      scwin.f_FormEnableChange(true);
      break;
    case "CANCEL":
      //취소
      scwin.f_Set("RETRIEVE");
      break;
    case "CREATE":
      //신규   
      scwin.processFlag = "CREATE";
      $c.gus.cfDisableBtnOnly($p, [btn_Create, btn_Update, btn_Delete]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel]);
      dlt_partnerInvoiceList.setCellData(dlt_partnerInvoiceList.getRowPosition(), "intendDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));
      dlt_invoiceCommon.setCellData(0, "confirmDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));
      dlt_invoiceCommon.setCellData(0, "bilgIntendDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));
      dlt_purchaseCerti.setCellData(0, "pchsIntendDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));
      scwin.f_FormEnableChange(false);

      // $c.gus.cfEnableObjects([ed_bilgIntendDt, ed_clntBilgDocNo, ed_bilgPicNo, bilgPicNm, txt_bilgPicNm]);
      ed_bilgIntendDt.focus();
      break;
    case "UPDATE":
      $c.gus.cfDisableBtnOnly($p, [btn_Create, btn_Update, btn_Delete]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel]);
      scwin.f_FormEnableChange(false);
      ed_bilgIntendDt.focus();
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel]);
      $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Create, btn_Delete]);
      scwin.f_Set("RETRIEVE");
      break;
    case "DELETE":
      cfDisableBtnOnly([btn_Save, btn_Cancel]);
      cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
      scwin.f_Set("RETRIEVE");
      break;
  }
};
scwin.f_FormEnableChange = function (flag) {
  ed_bilgIntendDt.setReadOnly(flag);
  ed_clntBilgDocNo.setReadOnly(flag);
  ed_bilgPicNo.setReadOnly(flag);
  img_bilgPicNo.setDisabled(flag);
  txt_bilgPicNm.setReadOnly(flag);
};

