scwin.btn_retrieve_onclick = function (e) {
  scwin.f_Retrieve();
};
scwin.f_Retrieve = function () {
  dlt_partnerFreight.removeAll();
  if ($c.util.isEmpty($p, cnd_ed_mblno.getValue()) && $c.util.isEmpty($p, cnd_ed_blno.getValue())) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, Array("Master or House B/L"));
    cnd_ed_mblno.focus();
    return;
  }

  // Console No 체크
  if ($c.util.isEmpty($p, cnd_lc_mhno.getValue())) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, Array("Console No"));
    return;
  }

  //dataset clear
  dlt_partnerInvoiceList.removeAll();
  dlt_invoiceCommon.removeAll();
  dlt_purchaseCerti.removeAll();
  dlt_partnerFreight.removeAll();
  $c.sbm.execute($p, sbm_retrieve);
};

